use std::io::{self, Write};

struct SimulationParameters {
    mass: f64,
    initial_velocity: (f64, f64),
}

fn get_user_input() -> io::Result<SimulationParameters> {
    let mut params = SimulationParameters { 
        mass: 0.0,
        initial_velocity: (0.0, 0.0),
    };

    writeln!(io::stdout(), "Please enter the mass of the object in kilograms:");
    io::stdout().flush()?;

    let mut input = String::new();
    io::stdin().read_line(&mut input)?; 
    params.mass = input.trim().parse().unwrap_or(1.0);

    writeln!(io::stdout(), "Next, what is the starting X speed? (e.g., 5.0)");
    io::stdout().flush()?;
    let mut input = String::new();
    io::stdin().read_line(&mut input)?; 
    let x_vel = input.trim().parse().unwrap_or(1.0);

    writeln!(io::stdout(), "Finally, what is the starting Y speed? (e.g., 2.5)");
    io::stdout().flush()?;
    let mut input = String::new();
    io::stdin().read_line(&mut input)?; 
    let y_vel = input.trim().parse().unwrap_or(1.0);
    params.initial_velocity = (x_vel, y_vel);

    Ok(params)
}

fn main() -> io::Result<()> {
    let parameters = get_user_input()?;

    println!("n--- Simulation Setup Complete ---");
    println!("Object Mass: {:.2} kg", parameters.mass);
    println!("Initial Velocity: ({:.2}, {:.2})", 
        parameters.initial_velocity.0, parameters.initial_velocity.1);

    Ok(())
}

use std::collections::HashMap;
use std::sync::atomic::{AtomicUsize, Ordering};

struct DataLoader {
    call_count: AtomicUsize,
    cache: HashMap<i32, String>,
}

impl DataLoader {
    fn new() -> Self {
        DataLoader {
            call_count: AtomicUsize::new(0),
            cache: HashMap::new(),
        }
    }

    async fn load(&mut self, keys: Vec<i32>) -> HashMap<i32, String> {
        if keys.is_empty() {
            return HashMap::new();
        }

        println!("--- Batch loading started for {} keys ---", keys.len());
        self.call_count.fetch_add(1, Ordering::SeqCst);

        let mut results = HashMap::new();

        for key in keys {
            if let Some(data) = self.cache.get(&key) {
                results.insert(key, data.clone());
                continue;
            }

            println!("Simulating DB lookup for key: {}", key);
            tokio::time::sleep(std::time::Duration::from_millis(5)).await;
            let simulated_result = format!("Data for {}", key);
            self.cache.insert(key, simulated_result.clone());
            results.insert(key, simulated_result);
        }

        println!("--- Batch loading finished ---n");
        results
    }

    fn get_call_count(&self) -> usize {
        self.call_count.load(Ordering::SeqCst)
    }
}

#[tokio::main]
async fn main() {
    let mut loader = DataLoader::new();

    let keys1 = vec![1, 2, 3];
    let results1 = loader.load(keys1).await;
    println!("Received: {:?}", results1);

    let keys2 = vec![3, 4, 1];
    let results2 = loader.load(keys2).await;
    println!("Received: {:?}", results2);

    println!("Total simulated database calls made: {}", loader.get_call_count());
}

